-- 0090_revert_flips_facturas_solo_dbase.sql
-- TMT 2026-06-11 URGENTE (dueña): "cargaste de más — solo las que estaban en
-- dBase". Remediación del bulk-flip erróneo de hoy (296 backfill→carga sin
-- aparear): TOTF PC quedó +355k sobre el dBase.
--
-- 1) Revertir TODOS los flips de hoy (distinguibles: asinfo-carga con
--    fecha_crea anterior al 10/06 = filas nacidas como backfill).
UPDATE scintela.factura
   SET usuario_crea = 'asinfo-backfill'
 WHERE usuario_crea = 'asinfo-carga'
   AND fecha_crea < DATE '2026-06-10';

-- 2) Re-activar SOLO las apareadas 1 a 1 contra la cartera VIVA del dBase
--    (FACTURAS.DBF del tarball final, stat ZA saldo<>0): el numf del N° SRI
--    debe estar en la lista de NUMF vivos. Ventana = la de los flips.
UPDATE scintela.factura
   SET usuario_crea = 'asinfo-carga'
 WHERE usuario_crea = 'asinfo-backfill'
   AND fecha >= DATE '2026-05-12' AND fecha <= DATE '2026-06-10'
   AND numf_completo ~ '[0-9]{4,}$'
   AND (regexp_replace(numf_completo, '^.*[^0-9]', ''))::bigint IN (174007,174009,174010,174017,174019,174020,174021,174023,174024,174026,174027,174029,174033,174035,174037,174039,174042,174044,174046,174047,174048,174050,174052,174054,174056,174062,174063,174065,174066,174067,174068,174069,174072,174075,174079,174080,174081,174082,174083,174090,174098,174101,174102,174109,174110,174111,174112,174113,174116,174117,174119,174121,174122,174125,174126,174128,174129,174130,174135,174137,174138,174142,174145,174146,174147,174149,174151,174155,174156,174157,174160,174165,174177,174179,174182,174184,174188,174191,174193,174197,174198,174199,174200,174202,174204,174205,174216,174220,174229,174234,174238,174239,174257,174264,174265,174266,174267,174269,174272,174279,174280,174284,174287,174289,174291,174292,174294,174295,174296,174298,174299,174300,174301,174303,174308,174312,174315,174316,174319,174322,174324,174325,174326,174327,174329,174330,174331,174332,174337,174338,174339,174341,174342,174343,174345,174346,174348,174349,174352,174353,174360,174362,174366,174367,174368,174369,174370,174371,174375,174376,174377,174378,174379,174380,174381,174383,174385,174386,174388,174389,174391,174392,174394,174395,174396,174397,174398,174399,174400,174402,174406,174408,174413,174416,174417,174420,174421,174422,174424,174426,174427,174429,174431,174433,174434,174438,174445,174446,174448,174449,174454,174456,174460,174461,174462,174463,174464,174465,174466,174467,174468,174469,174471,174472,174473,174476,174477,174478,174479,174480,174481,174484,174486,174487,174488,174489,174491,174492,174494,174497,174499,174500,174501,174502,174503,174506,174508,174517,174519,174520,174522,174525,174531,174532,174535,174537,174538,174539,174541,174542,174544,174547,174548,174550,174552,174553,174556,174559,174560,174562,174563,174565,174572,174578,174580,174584,174585,174586,174587,174588,174593,174595,174601,174606,174614,174615,174616,174618,174619,174621,174622,174623,174624,174626,174629,174630,